            if (parentDir != null && !parentDir.exists()) {
                if (!parentDir.mkdirs()) {
                    return false;
                }
            }

            // Handle null content by treating it as empty string
            String contentToWrite = content != null ? content : "";

            // Write content to file
            try (FileWriter writer = new FileWriter(requestedPath.toFile())) {
                writer.write(contentToWrite);
                writer.flush();
            }

            return true;

